// เลือกไฟล์ KB ที่จะส่งเข้า context (ADR-003) — เรียง path แบบ deterministic เพื่อ prompt cache
const tree = $input.first().json.tree || [];
const keep = /^(README\.md|CONTRIBUTING\.md|prompts\/qa-system\.md|domains\/.+\.md|guides\/.+\.md|plans\/.+\.md|glossary\/.+\.md)$/;
const files = tree
  .filter(t => t.type === 'blob' && keep.test(t.path))
  .sort((a, b) => a.path.localeCompare(b.path));
if (files.length === 0) throw new Error('no KB files matched');
return files.map(f => ({ json: { path: f.path, url: f.url } }));

const paths = $('Pick Files').all().map(i => i.json.path);
const blobs = $input.all();
if (paths.length !== blobs.length) throw new Error('path/blob count mismatch');
const question = ($('Webhook').first().json.body || {}).text;
if (!question) throw new Error('body.text (question) required');

let systemPrompt = 'คุณคือ Javis ผู้ช่วยคลังความรู้ของทีม ตอบจากเอกสารเท่านั้น ใช้ citations เสมอ';
const documents = [];
for (let i = 0; i < paths.length; i++) {
  const raw = blobs[i].json.content || '';
  const text = Buffer.from(raw.replace(/\n/g, ''), 'base64').toString('utf8');
  if (paths[i] === 'prompts/qa-system.md') {
    const m = text.match(/```([\s\S]*?)```/);
    if (m) systemPrompt = m[1].trim();
    continue;
  }
  documents.push({
    type: 'document',
    source: { type: 'text', media_type: 'text/plain', data: text },
    title: paths[i],
    citations: { enabled: true }
  });
}
// cache breakpoint ที่ document สุดท้าย — ครอบ system + เอกสารทั้งหมด (ADR-003)
documents[documents.length - 1].cache_control = { type: 'ephemeral' };

const body = {
  model: 'claude-sonnet-5',
  max_tokens: 2048,
  output_config: { effort: 'low' },
  system: [{ type: 'text', text: systemPrompt }],
  messages: [{
    role: 'user',
    content: [
      ...documents,
      { type: 'text', text: 'ใช้ citations ประกอบทุกข้อเท็จจริงเสมอ\n\nคำถาม: ' + question }
    ]
  }]
};
return [{ json: { body: JSON.stringify(body), doc_count: documents.length } }];

const resp = $input.first().json;
let answer = '';
const cited = new Set();
for (const block of resp.content || []) {
  if (block.type === 'text') {
    answer += block.text;
    for (const c of block.citations || []) cited.add(c.document_title);
  }
}
return [{ json: {
  answer,
  citations: [...cited],
  model: resp.model,
  stop_reason: resp.stop_reason,
  usage: resp.usage
} }];
